import React, { useLayoutEffect, useState } from 'react';
import { Canvas, useThree } from '@react-three/fiber';
import { OrbitControls, SoftShadows, Edges } from '@react-three/drei';
import * as THREE from 'three';
import { PatternParams, StripData } from '../types';
import { PAPER_W, PAPER_H } from '../geometry';

interface Props {
  params: PatternParams;
  strips: StripData[];
  foldProgress: number; // 0 (Flat) to 1 (Open 90 degrees)
}

// Sub-component for a single paper strip plane
// Handles material, stress coloring, and edge rendering safely
const StripPlane: React.FC<{
  width: number;
  height: number;
  color: string;
  tension?: number;
  isGhost?: boolean;
  showStress?: boolean;
  opacity?: number;
}> = ({ width, height, color, tension = 0, isGhost = false, showStress = false, opacity = 1.0 }) => {
  if (width <= 0 || height <= 0) return null;

  const finalColor = React.useMemo(() => {
    const c = new THREE.Color(color);
    if (showStress && !isGhost) {
      const t = Math.min(1.0, Math.max(0, tension));
      const safeColor = new THREE.Color('#ffffff');
      const warnColor = new THREE.Color('#ef4444');
      c.lerpColors(safeColor, warnColor, t * t);
    }
    return c;
  }, [color, showStress, isGhost, tension]);

  const edgeColor = isGhost ? "#a0a0a0" : "#cbd5e1";

  return (
    <mesh castShadow receiveShadow>
      <planeGeometry args={[width, height]} />
      <meshPhysicalMaterial
        color={finalColor}
        side={THREE.DoubleSide}
        roughness={0.9}
        metalness={0.0}
        transmission={isGhost ? 0 : 0.25}
        thickness={2.5}
        attenuationColor="#ffedd5"
        attenuationDistance={10.0}
        polygonOffset={true}
        polygonOffsetFactor={isGhost ? 2 : 1}
        polygonOffsetUnits={1}
        transparent={opacity < 1.0}
        opacity={opacity}
      />
      {!isGhost && (
        <Edges color={edgeColor} threshold={15}>
           <lineBasicMaterial color={edgeColor} transparent opacity={0.3 * opacity} />
        </Edges>
      )}
    </mesh>
  );
};

// Reusable component to render the mesh at a specific state
const KirigamiMesh: React.FC<{
  params: PatternParams;
  strips: StripData[];
  foldProgress: number;
  opacity?: number;
  isGhost?: boolean;
}> = ({ params, strips, foldProgress, opacity = 1.0, isGhost = false }) => {
  const { gap, physicsMode, showStress } = params;

  // Animation State: -90deg (Flat) to 0deg (Upright)
  const topRotation = -Math.PI / 2 + (foldProgress * Math.PI / 2);

  const renderElements = () => {
    const elements = [];

    if (strips.length === 0) return null;

    const firstStrip = strips[0];
    const lastStrip = strips[strips.length - 1];

    const minX = firstStrip.x - firstStrip.width / 2;
    const maxX = lastStrip.x + lastStrip.width / 2;
    const totalPatternWidth = maxX - minX;

    const marginWidth = Math.max(0, (PAPER_W - totalPatternWidth) / 2);

    const leftX = -PAPER_W/2 + marginWidth/2;
    const rightX = PAPER_W/2 - marginWidth/2;

    // 1. Margins / Base Paper Frame
    const botLen = PAPER_H / 2;
    const botZ = botLen / 2;

    elements.push(
      <group position={[leftX, 0, botZ]} rotation={[-Math.PI / 2, 0, 0]} key="margin_l_bot">
        <StripPlane width={marginWidth} height={botLen} color='#fdfbf7' isGhost={isGhost} opacity={opacity} />
      </group>
    );
    elements.push(
      <group position={[rightX, 0, botZ]} rotation={[-Math.PI / 2, 0, 0]} key="margin_r_bot">
        <StripPlane width={marginWidth} height={botLen} color='#fdfbf7' isGhost={isGhost} opacity={opacity} />
      </group>
    );

    const topLen = PAPER_H / 2;
    const topY = topLen / 2; 

    elements.push(
      <group rotation={[topRotation, 0, 0]} key="margin_l_top">
         <group position={[leftX, topY, 0]}>
            <StripPlane width={marginWidth} height={topLen} color='#fdfbf7' isGhost={isGhost} opacity={opacity} />
         </group>
      </group>
    );
    elements.push(
      <group rotation={[topRotation, 0, 0]} key="margin_r_top">
         <group position={[rightX, topY, 0]}>
            <StripPlane width={marginWidth} height={topLen} color='#fdfbf7' isGhost={isGhost} opacity={opacity} />
         </group>
      </group>
    );

    // 2. Strips
    strips.forEach((strip, i) => {
        const localX = strip.x;
        const rise = strip.rise;
        const run = strip.run;

        // A. Top Strip Segment
        let stripTopLen = (PAPER_H / 2) - rise;

        if (stripTopLen > 0 || physicsMode === 'IMPOSSIBLE') {
          const visLen = Math.abs(stripTopLen); 
          const stripTopCenterY = rise + stripTopLen / 2;

          elements.push(
              <group key={`strip_top_${i}`} rotation={[topRotation, 0, 0]}>
                  <group position={[localX, stripTopCenterY, 0]}>
                      <StripPlane width={strip.width} height={visLen} color='#fdfbf7' isGhost={isGhost} opacity={opacity} />
                  </group>
              </group>
          );
        }

        // B. Bottom Strip Segment
        let stripBotLen = (PAPER_H / 2) - run;
        if (stripBotLen > 0 || physicsMode === 'IMPOSSIBLE') {
          const visLen = Math.abs(stripBotLen);
          const stripBotCenterZ = run + stripBotLen / 2;
          elements.push(
              <group key={`strip_bot_${i}`} position={[localX, 0, stripBotCenterZ]} rotation={[-Math.PI / 2, 0, 0]}>
                  <StripPlane width={strip.width} height={visLen} color='#fdfbf7' isGhost={isGhost} opacity={opacity} />
              </group>
          );
        }

        // C. Pop-up Mechanism
        const pTop = new THREE.Vector3(localX, rise * Math.cos(topRotation), rise * Math.sin(topRotation));
        const pBot = new THREE.Vector3(localX, 0, run);

        // Distance between anchors
        const dy = pBot.y - pTop.y;
        const dz = pBot.z - pTop.z;
        const d2 = dy*dy + dz*dz;
        const d = Math.sqrt(d2);

        // Theoretical Max Length of the strip pieces (Riser + Tread)
        const totalStripLength = rise + run;

        // Calculate Tension
        let tension = 0;
        if (totalStripLength > 0.001) {
            tension = d / totalStripLength;
            tension = (tension - 0.9) * 10; 
        }

        let pKnee: THREE.Vector3 | null = null;
        let isImpossible = false;

        // REALISTIC MODE
        if (physicsMode === 'REALISTIC') {
             if (d > 0.001 && d <= totalStripLength + 0.1) {
                if (Math.abs(d - totalStripLength) < 0.1) {
                     const ratio = rise / totalStripLength;
                     pKnee = new THREE.Vector3().lerpVectors(pTop, pBot, ratio);
                } else {
                     const r1 = rise;
                     const r2 = run;
                     const a = (r1*r1 - r2*r2 + d2) / (2*d);
                     const hArg = r1*r1 - a*a;
                     const h = Math.sqrt(Math.max(0, hArg));

                     const y2 = pTop.y + a * (dy / d);
                     const z2 = pTop.z + a * (dz / d);
                     const y3_1 = y2 + h * (dz / d); 
                     const z3_1 = z2 - h * (dy / d); 
                     const y3_2 = y2 - h * (dz / d);
                     const z3_2 = z2 + h * (dy / d);

                     const distSq1 = y3_1*y3_1 + z3_1*z3_1;
                     const distSq2 = y3_2*y3_2 + z3_2*z3_2;
                     pKnee = (distSq1 > distSq2) ? new THREE.Vector3(localX, y3_1, z3_1) : new THREE.Vector3(localX, y3_2, z3_2);
                }
             }
        } 
        // IMPOSSIBLE MODE
        else {
             isImpossible = d > totalStripLength;

             if (!isImpossible) {
                if (Math.abs(d - totalStripLength) < 0.1) {
                     const ratio = rise / totalStripLength;
                     pKnee = new THREE.Vector3().lerpVectors(pTop, pBot, ratio);
                } else {
                     const r1 = rise;
                     const r2 = run;
                     const a = (r1*r1 - r2*r2 + d2) / (2*d);
                     const hArg = r1*r1 - a*a;
                     const h = Math.sqrt(Math.max(0, hArg));
                     const y2 = pTop.y + a * (dy / d);
                     const z2 = pTop.z + a * (dz / d);
                     const y3_1 = y2 + h * (dz / d); 
                     const z3_1 = z2 - h * (dy / d); 
                     const y3_2 = y2 - h * (dz / d);
                     const z3_2 = z2 + h * (dy / d);
                     const distSq1 = y3_1*y3_1 + z3_1*z3_1;
                     const distSq2 = y3_2*y3_2 + z3_2*z3_2;
                     pKnee = (distSq1 > distSq2) ? new THREE.Vector3(localX, y3_1, z3_1) : new THREE.Vector3(localX, y3_2, z3_2);
                }
             } else {
                 const ratio = rise / (rise + run);
                 pKnee = new THREE.Vector3().lerpVectors(pTop, pBot, ratio);
             }
        }

        if (pKnee) {
             const riserColor = isImpossible ? '#a855f7' : '#fdfbf7';
             const treadColor = isImpossible ? '#d8b4fe' : '#fdfbf7';

             // Riser Segment
             const diffRiser = new THREE.Vector3().subVectors(pKnee, pTop);
             const lenRiser = diffRiser.length();
             if (lenRiser > 0.01) {
                const midRiser = new THREE.Vector3().addVectors(pTop, pKnee).multiplyScalar(0.5);
                const angleXRiser = Math.atan2(diffRiser.z, diffRiser.y);
                elements.push(
                  <group key={`riser_${i}`} position={midRiser} rotation={[angleXRiser, 0, 0]}>
                    <StripPlane width={strip.width} height={lenRiser} color={riserColor} tension={tension} isGhost={isGhost} showStress={showStress} opacity={opacity} />
                  </group>
                );
             }

             // Tread Segment
             const diffTread = new THREE.Vector3().subVectors(pBot, pKnee);
             const lenTread = diffTread.length();
             if (lenTread > 0.01) {
                const midTread = new THREE.Vector3().addVectors(pKnee, pBot).multiplyScalar(0.5);
                const angleXTread = Math.atan2(diffTread.z, diffTread.y);
                elements.push(
                  <group key={`tread_${i}`} position={midTread} rotation={[angleXTread, 0, 0]}>
                    <StripPlane width={strip.width} height={lenTread} color={treadColor} tension={tension} isGhost={isGhost} showStress={showStress} opacity={opacity} />
                  </group>
                );
             }
        }

        // Gap Fillers
        if (i < strips.length - 1 && gap > 0) {
            const gapX = localX + strip.width/2 + gap/2;
            elements.push(
               <group key={`gap_bot_${i}`} position={[gapX, 0, botZ]} rotation={[-Math.PI / 2, 0, 0]}>
                  <StripPlane width={gap} height={botLen} color='#fdfbf7' isGhost={isGhost} opacity={opacity} />
               </group>
            );
            elements.push(
              <group key={`gap_top_${i}`} rotation={[topRotation, 0, 0]}>
                 <group position={[gapX, topY, 0]}>
                   <StripPlane width={gap} height={topLen} color='#fdfbf7' isGhost={isGhost} opacity={opacity} />
                 </group>
              </group>
            );
        }
    });

    return <group>{elements}</group>;
  };

  return <group>{renderElements()}</group>;
};

// Main Scene Component handling lights and multiple render passes
const SceneContent: React.FC<Props> = (props) => {
    const { camera } = useThree();

    useLayoutEffect(() => {
        camera.position.set(250, 350, 350);
        camera.lookAt(0, 50, 0);
    }, [camera]);

    const { showGhostTrails, lampAngle, lampHeight, lampDistance } = props.params;

    // Calculate Lamp Position
    const angleRad = (lampAngle * Math.PI) / 180;
    const lightX = Math.sin(angleRad) * lampDistance;
    const lightZ = Math.cos(angleRad) * lampDistance;
    const lightY = lampHeight;

    // Use state initializer to create a stable Object3D for the light target
    // This avoids "read-only property" errors associated with primitive updates in R3F
    const [lightTarget] = useState(() => {
        const t = new THREE.Object3D();
        t.position.set(0, 0, 0);
        return t;
    });

    return (
        <>
            <ambientLight intensity={0.4} />

            {/* Dynamic Desk Lamp */}
            {/* We place the target in the scene graph so the spotlight can point to it */}
            <primitive object={lightTarget} />

            <spotLight 
                target={lightTarget}
                position={[lightX, lightY, lightZ]} 
                angle={0.5} 
                penumbra={0.4} 
                intensity={1.2} 
                castShadow 
                shadow-bias={-0.001}
                shadow-mapSize-width={2048}
                shadow-mapSize-height={2048}
            />
            {/* Lamp Bulb Visualizer (Tiny dot) */}
            <mesh position={[lightX, lightY, lightZ]}>
                <sphereGeometry args={[10]} />
                <meshBasicMaterial color="#fbbf24" />
            </mesh>

            {/* Backlight / Rim Light for SSS Effect */}
            <pointLight position={[0, 100, -300]} intensity={0.5} color="#e0f2fe" />

            {/* Soft Shadows wrapper */}
            <SoftShadows size={15} focus={1} samples={10} />

            <group position={[0, -50, 0]}>

                {/* 1. Speculative Ghost Trails */}
                {showGhostTrails && (
                    <>
                        <KirigamiMesh {...props} foldProgress={props.foldProgress * 0.3} opacity={0.2} isGhost={true} />
                        <KirigamiMesh {...props} foldProgress={props.foldProgress * 0.6} opacity={0.3} isGhost={true} />
                        <KirigamiMesh {...props} foldProgress={props.foldProgress * 0.8} opacity={0.4} isGhost={true} />
                    </>
                )}

                {/* 2. Main Mesh */}
                <KirigamiMesh {...props} />

                {/* Floor Plane to catch shadows */}
                <mesh rotation={[-Math.PI/2, 0, 0]} position={[0, -1, 0]} receiveShadow>
                     <planeGeometry args={[2000, 2000]} />
                     <meshStandardMaterial color="#f8fafc" roughness={1} metalness={0} />
                </mesh>

                <gridHelper args={[1000, 50, 0xcbd5e1, 0xf1f5f9]} position={[0, -0.5, 0]} />
            </group>

            <OrbitControls 
                minPolarAngle={0} 
                maxPolarAngle={Math.PI / 1.9}
                minDistance={100}
                maxDistance={900}
                target={[0, 50, 0]}
            />
        </>
    );
};

export const Visualizer3D: React.FC<Props> = (props) => {
  return (
    <div className="h-full w-full bg-slate-50">
      <Canvas shadows dpr={[1, 2]}>
          <SceneContent {...props} />
      </Canvas>
    </div>
  );
};
